/**
 * Sherwood QR Card Allowance Prototype — Google Sheets sync script.
 *
 * Sheet columns:
 * Stripe card ID | Last four | Allowance | Currency | Active | Sync status | Updated time | PIN once
 *
 * Setup:
 * 1. Extensions -> Apps Script.
 * 2. Project Settings -> Script Properties:
 *    - SHERWOOD_SYNC_URL = https://YOUR_DOMAIN/api/admin/cards/sync
 *    - SHERWOOD_SYNC_TOKEN = same value as ADMIN_SYNC_TOKEN in Vercel
 * 3. Reload the sheet; use Sherwood -> Sync allowance rows.
 *
 * Security:
 * - PINs are generated by the API or entered manually, then shown once in "PIN once".
 * - The API hashes PINs before storage; this sheet should be limited to trusted staff.
 */

const HEADERS = [
  "Stripe card ID",
  "Last four",
  "Allowance",
  "Currency",
  "Active",
  "Sync status",
  "Updated time",
  "PIN once",
];

function onOpen() {
  SpreadsheetApp.getUi()
    .createMenu("Sherwood")
    .addItem("Prepare sheet", "prepareSheet")
    .addItem("Sync allowance rows", "syncAllowanceRows")
    .addItem("Generate/reset PINs", "generatePinsForSelectedRows")
    .addToUi();
}

function prepareSheet() {
  const sheet = SpreadsheetApp.getActiveSheet();
  sheet.getRange(1, 1, 1, HEADERS.length).setValues([HEADERS]);
  sheet.setFrozenRows(1);
  sheet.autoResizeColumns(1, HEADERS.length);
}

function syncAllowanceRows() {
  const props = PropertiesService.getScriptProperties();
  const syncUrl = props.getProperty("SHERWOOD_SYNC_URL");
  const token = props.getProperty("SHERWOOD_SYNC_TOKEN");
  if (!syncUrl || !token) throw new Error("Missing SHERWOOD_SYNC_URL or SHERWOOD_SYNC_TOKEN.");

  const sheet = SpreadsheetApp.getActiveSheet();
  const lastRow = sheet.getLastRow();
  if (lastRow < 2) return;

  const rows = sheet.getRange(2, 1, lastRow - 1, HEADERS.length).getValues();
  const payloadCards = [];
  const rowNumbers = [];

  rows.forEach((row, index) => {
    const stripeCardId = String(row[0] || "").trim();
    if (!stripeCardId) return;

    const lastFour = String(row[1] || "").trim().replace(/\D/g, "");
    const allowanceCents = allowanceToCents(row[2]);
    const currency = String(row[3] || "usd").trim().toLowerCase();
    const active = parseActive(row[4]);
    const pin = String(row[7] || "").trim();

    payloadCards.push({
      stripe_card_id: stripeCardId,
      last_four: lastFour,
      allowance_cents: allowanceCents,
      currency,
      active,
      pin: pin && /^\d{6}$/.test(pin) ? pin : undefined,
    });
    rowNumbers.push(index + 2);
  });

  const response = UrlFetchApp.fetch(syncUrl, {
    method: "post",
    contentType: "application/json",
    headers: { Authorization: `Bearer ${token}` },
    payload: JSON.stringify({ cards: payloadCards }),
    muteHttpExceptions: true,
  });

  const json = JSON.parse(response.getContentText());
  if (response.getResponseCode() >= 400) {
    throw new Error(json.error || "Sync failed.");
  }

  json.results.forEach((result, index) => {
    const rowNumber = rowNumbers[index];
    const status = result.status === "error" ? `ERROR: ${result.error}` : result.status.toUpperCase();
    sheet.getRange(rowNumber, 6).setValue(status);
    sheet.getRange(rowNumber, 7).setValue(new Date());
    if (result.pin_once) {
      sheet.getRange(rowNumber, 8).setValue(result.pin_once);
      sheet.getRange(rowNumber, 8).setNote("Show this PIN once, then clear this cell.");
    }
  });
}

function generatePinsForSelectedRows() {
  const props = PropertiesService.getScriptProperties();
  const syncUrl = props.getProperty("SHERWOOD_SYNC_URL");
  const token = props.getProperty("SHERWOOD_SYNC_TOKEN");
  if (!syncUrl || !token) throw new Error("Missing SHERWOOD_SYNC_URL or SHERWOOD_SYNC_TOKEN.");

  const sheet = SpreadsheetApp.getActiveSheet();
  const selection = sheet.getActiveRange();
  const startRow = Math.max(selection.getRow(), 2);
  const rowCount = selection.getNumRows();
  const rows = sheet.getRange(startRow, 1, rowCount, HEADERS.length).getValues();

  const payloadCards = rows
    .map((row) => ({
      stripe_card_id: String(row[0] || "").trim(),
      last_four: String(row[1] || "").trim().replace(/\D/g, ""),
      allowance_cents: allowanceToCents(row[2]),
      currency: String(row[3] || "usd").trim().toLowerCase(),
      active: parseActive(row[4]),
      generate_pin: true,
    }))
    .filter((row) => row.stripe_card_id);

  const response = UrlFetchApp.fetch(syncUrl, {
    method: "post",
    contentType: "application/json",
    headers: { Authorization: `Bearer ${token}` },
    payload: JSON.stringify({ cards: payloadCards }),
    muteHttpExceptions: true,
  });

  const json = JSON.parse(response.getContentText());
  if (response.getResponseCode() >= 400) throw new Error(json.error || "PIN reset failed.");

  json.results.forEach((result, index) => {
    const rowNumber = startRow + index;
    sheet.getRange(rowNumber, 6).setValue(result.status === "error" ? `ERROR: ${result.error}` : "PIN RESET");
    sheet.getRange(rowNumber, 7).setValue(new Date());
    if (result.pin_once) {
      sheet.getRange(rowNumber, 8).setValue(result.pin_once);
      sheet.getRange(rowNumber, 8).setNote("Show this PIN once, then clear this cell.");
    }
  });
}

function allowanceToCents(value) {
  if (typeof value === "number") return Math.round(value * 100);
  const clean = String(value || "").replace(/[$,]/g, "").trim();
  const parsed = Number(clean);
  if (!Number.isFinite(parsed) || parsed < 0) return -1;
  return Math.round(parsed * 100);
}

function parseActive(value) {
  if (typeof value === "boolean") return value;
  const normalized = String(value || "true").trim().toLowerCase();
  return !["false", "no", "0", "inactive"].includes(normalized);
}
